from typing import AsyncGenerator
from fastapi import Depends
from sqlalchemy.ext.asyncio import AsyncSession
from src.db.database import AsyncSessionLocal
from src.web.services.batch_service import BatchService
from src.web.services.query_service import QueryService

async def get_db() -> AsyncGenerator[AsyncSession, None]:
    async with AsyncSessionLocal() as session:
        try:
            yield session
        finally:
            await session.close()

def get_batch_service(db: AsyncSession = Depends(get_db)) -> BatchService:
    return BatchService(db)

def get_query_service(db: AsyncSession = Depends(get_db)) -> QueryService:
    return QueryService(db)

