from sqlalchemy import select, func
from sqlalchemy.orm import load_only

async def get_dashboard_stats(db: AsyncSession):
    # Use select_only to fetch specific columns
    stmt = select(
        func.count(RawMarkdown.id).label('total'),
        func.count().filter(RawMarkdown.processing_status == 'pending').label('pending'),
        func.count().filter(RawMarkdown.processing_status == 'processing').label('processing'),
        func.count().filter(RawMarkdown.processing_status == 'completed').label('completed'),
        func.count().filter(RawMarkdown.processing_status == 'failed').label('failed')
    )

    result = await db.execute(stmt)
    return result.one()

async def get_paper_leads_paginated(db: AsyncSession, page: int = 1, per_page: int = 50):
    # Pagination with offset/limit
    offset = (page - 1) * per_page

    stmt = select(PaperLead)\
        .options(load_only(PaperLead.doi, PaperLead.author, PaperLead.email, PaperLead.score))\
        .order_by(PaperLead.created_at.desc())\
        .offset(offset)\
        .limit(per_page)

    result = await db.execute(stmt)
    return result.scalars().all()

